/**
 * @name Path traversal via taint flow from HTTP input to File constructor
 * @description User-controlled input flows to file system operations without adequate sanitization
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-http-to-file
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileInputStream / FileOutputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get()
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: user input flows to file system operation from $@.", source.getNode(), "user input"

/**
 * @name TemplateManager resource path traversal via getResourceAsStream
 * @description User-controlled input flows to ClassLoader.getResource or getResourceAsStream enabling classpath path traversal
 * @kind path-problem
 * @problem.severity error
 * @id java/template-manager-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module TemplatePathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ServletContext.getResource / getResourceAsStream  
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream") or
       mc.getMethod().hasName("getRealPath")) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet", "ServletContext") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module TemplatePathFlow = TaintTracking::Global<TemplatePathConfig>;
import TemplatePathFlow::PathGraph

from TemplatePathFlow::PathNode source, TemplatePathFlow::PathNode sink
where TemplatePathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Classpath/resource path traversal: user input flows to resource loading from $@.", source.getNode(), "user input"

/**
 * @name TemplateManager HTTP request parameter flowing to resource loading
 * @description HTTP request parameters control which template/resource file is loaded
 * @kind path-problem
 * @problem.severity error
 * @id java/template-manager-resource-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module TemplateResourceConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.wiki.ui", "TemplateManager") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // getResourceAsStream calls in TemplateManager
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.apache.wiki.ui", "TemplateManager") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module TemplateResourceFlow = TaintTracking::Global<TemplateResourceConfig>;
import TemplateResourceFlow::PathGraph

from TemplateResourceFlow::PathNode source, TemplateResourceFlow::PathNode sink
where TemplateResourceFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "TemplateManager resource path controlled by user input from $@.", source.getNode(), "user input"

/**
 * @name HTTP request skin/template parameter flows to TemplateManager resource loading
 * @description User-controlled skin or template parameter flows into resource loading in TemplateManager
 * @kind path-problem
 * @problem.severity error
 * @id java/template-skin-param-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module TemplateSkinConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Sinks: getResourceAsStream and findResource calls in TemplateManager
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResourceAsStream") or 
       mc.getMethod().hasName("findResource") or
       mc.getMethod().hasName("getResource")) and
      mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("org.apache.wiki.ui.TemplateManager") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Also catch any File constructor inside TemplateManager
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      ce.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("org.apache.wiki.ui.TemplateManager") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module TemplateSkinFlow = TaintTracking::Global<TemplateSkinConfig>;
import TemplateSkinFlow::PathGraph

from TemplateSkinFlow::PathNode source, TemplateSkinFlow::PathNode sink
where TemplateSkinFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled input in TemplateManager resource loading from $@.", source.getNode(), "user input"

/**
 * @name WikiAjaxDispatcherServlet path traversal - servlet name to dispatch
 * @description User-controlled servlet name in AJAX dispatcher may enable path traversal
 * @kind path-problem
 * @problem.severity error
 * @id java/ajax-dispatcher-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module AjaxDispatchConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Sinks in WikiAjaxDispatcherServlet
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("org.apache.wiki.ajax.WikiAjaxDispatcherServlet") and
      (mc.getMethod().hasName("get") or mc.getMethod().hasName("forName") or 
       mc.getMethod().hasName("invoke") or mc.getMethod().hasName("dispatch")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // File operations in ajax dispatcher
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      ce.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("org.apache.wiki.ajax.WikiAjaxDispatcherServlet") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module AjaxDispatchFlow = TaintTracking::Global<AjaxDispatchConfig>;
import AjaxDispatchFlow::PathGraph

from AjaxDispatchFlow::PathNode source, AjaxDispatchFlow::PathNode sink
where AjaxDispatchFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User input flows to WikiAjaxDispatcherServlet operation from $@.", source.getNode(), "user input"

/**
 * @name CookieAuthenticationLoginModule: cookie value used as filename
 * @description Cookie value used directly in file path construction enabling path traversal
 * @kind path-problem
 * @problem.severity error
 * @id java/cookie-auth-file-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module CookieFileConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Cookie value reading
    exists(MethodCall mc |
      mc.getMethod().hasName("getValue") and
      mc.getMethod().getDeclaringType().hasQualifiedName("javax.servlet.http", "Cookie") and
      source.asExpr() = mc
    )
    or
    // getCookies / cookie array access
    exists(MethodCall mc |
      mc.getMethod().hasName("getCookies") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletRequest") and
      source.asExpr() = mc
    )
    or
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Exclude non-cookie related flows not in auth module to reduce noise
    exists(Method m | 
      m = node.asExpr().getEnclosingCallable() and
      not m.getDeclaringType().getQualifiedName().matches("%Cookie%") and
      not m.getDeclaringType().getQualifiedName().matches("%Login%") and
      not m.getDeclaringType().getQualifiedName().matches("%Auth%")
    )
  }
}

module CookieFileFlow = TaintTracking::Global<CookieFileConfig>;
import CookieFileFlow::PathGraph

from CookieFileFlow::PathNode source, CookieFileFlow::PathNode sink
where CookieFileFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Cookie/HTTP value flows to file path construction from $@.", source.getNode(), "cookie/request value"

/**
 * @name Path traversal: user input to FileInputStream without validation
 * @description User-controlled input reaches FileInputStream without path validation
 * @kind path-problem
 * @problem.severity error
